//! E2e tests for category: rendering

use kreuzberg::{
    convert_html_to_markdown, djot_to_html, render_djot, render_html, render_json, render_markdown, render_plain,
};

#[test]
fn test_convert_html_basic() {
    // Convert basic HTML to Markdown format
    let html = r#"<h1>Title</h1><p>Paragraph text.</p><ul><li>Item 1</li><li>Item 2</li></ul>"#;
    let result = convert_html_to_markdown(&html).expect("should succeed");
    assert!(
        format!("{:?}", result.content).contains(r#"Title"#),
        "expected to contain: {}",
        r#"Title"#
    );
}

#[test]
fn test_convert_html_complex() {
    // Convert complex HTML to markdown
    let html = r#"<h1>Title</h1><p>Text with <strong>bold</strong> and <a href="https://example.com">link</a>.</p>"#;
    let result = convert_html_to_markdown(&html).expect("should succeed");
    assert!(
        result.content.len() >= 20,
        "expected length >= 20, got {}",
        result.content.len()
    );
}

#[test]
fn test_convert_html_empty() {
    // Convert empty HTML to markdown
    let html = r#""#;
    let _ = convert_html_to_markdown(&html);
}

#[test]
fn test_convert_html_table() {
    // Convert HTML table to Markdown table format
    let html = r#"<table><tr><th>Column A</th><th>Column B</th></tr><tr><td>1</td><td>2</td></tr><tr><td>3</td><td>4</td></tr></table>"#;
    let result = convert_html_to_markdown(&html).expect("should succeed");
    assert!(
        format!("{:?}", result.content).contains(r#"|"#),
        "expected to contain: {}",
        r#"|"#
    );
}

#[test]
